/**
 * One snapshot of a formula's output relation.
 *
 * The formula body is *inlined* at snapshot time so the snapshot stays
 * self-describing — editing the source Formula later does not mutate
 * this Observation. Re-snapshotting after edits creates a new one.
 *
 * There is no per-row provenance: **the inlined formula + run is the
 * provenance**. Re-running the same Formula over an unchanged run yields
 * the same relation because the query is the same. (Evidence-mode rows
 * carry their own ``annotation_id`` in ``output_blob`` intrinsically.)
 */
export type Observation = {
    id?: string;
    formula_inline: Formula;
    formula_name: string;
    computed_at?: string;
    output_blob?: Array<OutputRow>;
    output_keys?: Array<(string)>;
    run_id: number;
    schema_id_snapshot?: (number | null);
    notes?: (string | null);
};

/**
 * Optional sort override on the output relation.
 *
 * Default (when omitted): if any ``time`` dim is present, sort chronologic-
 * ally on the first time dim ASC; otherwise sort by the first non-derive
 * measure DESC (biggest-first — what pies/bars want).
 *
 * Explicit override: ``column`` names a dim, measure, or derive in the
 * formula; ``direction`` defaults to DESC. SQL-side push when the column
 * is a dim or aggregate measure; post-eval Python sort when the column is
 * a derive (≤5000 rows, free).
 */
export type OrderBy = {
    column: string;
    direction?: 'asc' | 'desc';
};

export type direction = 'asc' | 'desc';

/**
 * One row of a Formula's output relation: group keys × measures.
 *
 * ``annotation_id``/``asset_id``/``snippet`` are populated **only** in
 * evidence mode (a ``top(N)`` measure or a snippet binding) — there the
 * row *is* an annotation, so provenance is intrinsic and free. In pure
 * aggregate mode they are ``None``: the query itself is the provenance.
 */
export type OutputRow = {
    keys?: {
        [key: string]: (string);
    };
    measures?: {
        [key: string]: unknown;
    };
    annotation_id?: (number | null);
    asset_id?: (number | null);
    snippet?: (string | null);
};

